Create `apps/server/src/routes/mcp.ts` — an Express router factory that handles Streamable HTTP transport for the MCP protocol. Supports POST (JSON-RPC tool calls), and returns 405 for GET and DELETE (stateless mode).

**Implementation:**

Create `apps/server/src/routes/mcp.ts`:

```typescript
import { Router } from 'express';
import type { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import { NodeStreamableHTTPServerTransport } from '@modelcontextprotocol/sdk/server/node.js';
import { logger } from '../lib/logger.js';

/**
 * Create an Express router for the MCP Streamable HTTP endpoint.
 *
 * Handles POST requests with JSON-RPC bodies. GET and DELETE return 405
 * because this server operates in stateless mode (no session tracking).
 *
 * @param server - The shared McpServer instance with all tools registered
 */
export function createMcpRouter(server: McpServer): Router {
  const router = Router();

  // POST: JSON-RPC tool calls (primary endpoint)
  router.post('/', async (req, res) => {
    try {
      const transport = new NodeStreamableHTTPServerTransport({
        sessionIdGenerator: undefined, // stateless
      });
      await server.connect(transport);
      await transport.handleRequest(req, res, req.body);
    } catch (err) {
      logger.error('[MCP] Request handling error', err);
      if (!res.headersSent) {
        res.status(500).json({
          jsonrpc: '2.0',
          error: { code: -32603, message: 'Internal error' },
          id: null,
        });
      }
    }
  });

  // GET: Server-initiated SSE stream — not needed in stateless mode
  router.get('/', (_req, res) => {
    res.status(405).json({
      jsonrpc: '2.0',
      error: { code: -32000, message: 'Method not allowed. This server operates in stateless mode.' },
      id: null,
    });
  });

  // DELETE: Session termination — not applicable in stateless mode
  router.delete('/', (_req, res) => {
    res.status(405).json({
      jsonrpc: '2.0',
      error: { code: -32000, message: 'Method not allowed. This server operates in stateless mode.' },
      id: null,
    });
  });

  return router;
}
```

**Key design decisions:**
- **Per-request transport:** Each POST creates a new `NodeStreamableHTTPServerTransport` with `sessionIdGenerator: undefined` for stateless operation. The transport is lightweight — construction cost is negligible.
- **Pre-parsed body:** The DorkOS Express app already has `express.json({ limit: '1mb' })` middleware. The route passes `req.body` (pre-parsed) to `transport.handleRequest()` to avoid double-parsing.
- **Error handling:** Wraps the async call in try/catch. If `server.connect()` or `transport.handleRequest()` throws, returns a JSON-RPC error response. Checks `res.headersSent` to avoid double-response.
- **405 for GET/DELETE:** Stateless mode means no SSE streams and no session termination. These methods return 405 with descriptive JSON-RPC error messages.
- **JSON-RPC error codes:** `-32603` for internal errors (standard JSON-RPC), `-32000` for application-level method errors.

**Acceptance Criteria:**
- [ ] File `apps/server/src/routes/mcp.ts` exists
- [ ] `createMcpRouter(server)` returns an Express `Router`
- [ ] POST `/` creates per-request transport and handles JSON-RPC
- [ ] GET `/` returns 405 with JSON-RPC error
- [ ] DELETE `/` returns 405 with JSON-RPC error
- [ ] Error handling catches transport/server errors and returns JSON-RPC error
- [ ] TSDoc on exported function
- [ ] `pnpm typecheck` passes

Create `apps/server/src/middleware/mcp-origin.ts` — an Express middleware that validates the `Origin` header on MCP requests to prevent DNS rebinding attacks, as required by the MCP spec.

**Implementation:**

Create `apps/server/src/middleware/mcp-origin.ts`:

```typescript
import type { Request, Response, NextFunction } from 'express';
import { env } from '../env.js';
import { tunnelManager } from '../services/core/tunnel-manager.js';

/**
 * Origin validation middleware for the MCP endpoint.
 *
 * Prevents DNS rebinding attacks by validating the Origin header against
 * an allowlist of localhost origins and the active tunnel URL.
 *
 * Non-browser clients (curl, Claude Code CLI, etc.) send no Origin header
 * and pass through — this is correct per the MCP spec, which only requires
 * validation when an Origin header is present.
 */
export function validateMcpOrigin(req: Request, res: Response, next: NextFunction): void {
  const origin = req.headers.origin;

  // No origin header — non-browser client (curl, Claude Code, etc.) — allow
  if (!origin) {
    next();
    return;
  }

  // Check against allowed origins (localhost + tunnel)
  const port = env.DORKOS_PORT;
  const allowed = [
    `http://localhost:${port}`,
    `http://127.0.0.1:${port}`,
  ];

  // Add tunnel origin if active
  const tunnelUrl = tunnelManager.status.url;
  if (tunnelUrl) {
    allowed.push(new URL(tunnelUrl).origin);
  }

  if (!allowed.includes(origin)) {
    res.status(403).json({
      jsonrpc: '2.0',
      error: { code: -32002, message: `Origin ${origin} not allowed` },
      id: null,
    });
    return;
  }

  next();
}
```

**Key design decisions:**
- **Non-browser clients pass through.** The MCP spec states that Origin validation applies to browser-based requests. Non-browser clients (curl, Claude Code CLI, Agent SDK apps) do not send an Origin header and should not be blocked.
- **Dynamic tunnel origin.** The tunnel URL is checked at request time from `tunnelManager.status.url`, consistent with the existing dynamic CORS origin checker in `app.ts`.
- **JSON-RPC error format.** Returns a JSON-RPC error body (not REST) because the MCP endpoint speaks JSON-RPC.
- **Error code `-32002`.** Custom application error code for origin validation failures.
- **Middleware chain order:** `validateMcpOrigin` runs before `mcpApiKeyAuth` — origin validation is the first gate.

**Acceptance Criteria:**
- [ ] File `apps/server/src/middleware/mcp-origin.ts` exists
- [ ] `validateMcpOrigin` is exported
- [ ] Requests with no Origin header pass through
- [ ] Requests from `http://localhost:{DORKOS_PORT}` pass through
- [ ] Requests from `http://127.0.0.1:{DORKOS_PORT}` pass through
- [ ] Requests from tunnel origin pass through when tunnel is active
- [ ] Requests from unknown origins get 403 with JSON-RPC error body
- [ ] TSDoc on exported function
- [ ] `pnpm typecheck` passes

Create `apps/server/src/middleware/__tests__/mcp-auth.test.ts` — unit tests for the `mcpApiKeyAuth` middleware.

**Implementation:**

Create `apps/server/src/middleware/__tests__/mcp-auth.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { Request, Response, NextFunction } from 'express';

// Mock env module before importing the middleware
vi.mock('../../env.js', () => ({
  env: {
    MCP_API_KEY: undefined as string | undefined,
  },
}));

import { mcpApiKeyAuth } from '../mcp-auth.js';
import { env } from '../../env.js';

function createMockReq(authHeader?: string): Partial<Request> {
  return {
    headers: authHeader ? { authorization: authHeader } : {},
  };
}

function createMockRes(): Partial<Response> & { statusCode?: number; body?: unknown } {
  const res: Partial<Response> & { statusCode?: number; body?: unknown } = {};
  res.status = vi.fn().mockImplementation((code: number) => {
    res.statusCode = code;
    return res;
  }) as unknown as Response['status'];
  res.json = vi.fn().mockImplementation((data: unknown) => {
    res.body = data;
    return res;
  }) as unknown as Response['json'];
  return res;
}

describe('mcpApiKeyAuth', () => {
  let next: NextFunction;

  beforeEach(() => {
    next = vi.fn();
    // Reset to no key by default
    (env as { MCP_API_KEY: string | undefined }).MCP_API_KEY = undefined;
  });

  it('calls next() when MCP_API_KEY is not set', () => {
    const req = createMockReq();
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });

  it('calls next() when MCP_API_KEY is not set even with auth header', () => {
    const req = createMockReq('Bearer some-token');
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });

  it('calls next() when valid Bearer token matches MCP_API_KEY', () => {
    (env as { MCP_API_KEY: string | undefined }).MCP_API_KEY = 'test-secret-key';
    const req = createMockReq('Bearer test-secret-key');
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });

  it('returns 401 when MCP_API_KEY is set but no Authorization header', () => {
    (env as { MCP_API_KEY: string | undefined }).MCP_API_KEY = 'test-secret-key';
    const req = createMockReq();
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).not.toHaveBeenCalled();
    expect(res.statusCode).toBe(401);
    expect(res.body).toEqual({
      jsonrpc: '2.0',
      error: { code: -32001, message: 'Unauthorized. Set Authorization: Bearer <MCP_API_KEY>.' },
      id: null,
    });
  });

  it('returns 401 when token does not match MCP_API_KEY', () => {
    (env as { MCP_API_KEY: string | undefined }).MCP_API_KEY = 'correct-key';
    const req = createMockReq('Bearer wrong-key');
